window.addEventListener("load",()=>{const t=document.querySelector(".crt-logo");if(!t)return;t.style.setProperty("display","none","important");const e=new MutationObserver(()=>{t.style.setProperty("display","none","important"),document.querySelectorAll(".crt-logo").forEach(t=>{t.style.setProperty("display","none","important")})});e.observe(t,{attributes:!0,attributeFilter:["style"]})});